      .filter((r: Reminder) => r.petId === petId)
      .sort((a: Reminder, b: Reminder) => a.dueDate - b.dueDate)
      .map((r: Reminder) => this.toListItem(r))
  }

  upcomingByPet(petId: string, limit: number = 5): ReminderListItem[] {
    return this.listByPet(petId).filter((r: ReminderListItem) => !r.isDone).slice(0, limit)
  }

