      if (idx >= 0) {
        reminder.createdAt = this.reminders[idx].createdAt
        this.reminders[idx] = reminder
      } else {
        this.reminders.push(reminder)
      }
    }
    reminder.updatedAt = Date.now()
    await this.persist()
  }

